import NextAuth from "next-auth";
import CredentialsProvider from "next-auth/providers/credentials";

const handler = NextAuth({
  providers: [
    CredentialsProvider({
      name: "Admin Login",
      credentials: {
        email: { label: "البريد الإلكتروني", type: "email", placeholder: "admin@pcbuilder.com" },
        password: { label: "كلمة المرور", type: "password" }
      },
      async authorize(credentials) {
        // ضع الإيميل والباسورد الخاص بك هنا
        const adminEmail = "admin@pcbuilder.com";
        const adminPassword = "YourSecurePassword2026"; 

        if (credentials?.email === adminEmail && credentials?.password === adminPassword) {
          return { id: "1", name: "Admin", email: adminEmail };
        }
        
        return null; // فشل تسجيل الدخول
      }
    })
  ],
  pages: {
    // استخدم صفحة تسجيل الدخول الافتراضية
  },
  session: {
    strategy: "jwt",
  },
  secret: process.env.NEXTAUTH_SECRET || "fallback_secret_key_for_development",
});

export { handler as GET, handler as POST };